module RefModule(CLK, RST, Gray);
input CLK, RST;
output [1:0] Gray;
reg [1:0] Gray;
reg [1:0] unused_binary_counter;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        unused_binary_counter <= 0;
        Gray <= 0;
    end else begin
        unused_binary_counter <= unused_binary_counter + 1;
        Gray <= (unused_binary_counter >> 1) ^ unused_binary_counter;
    end
end

endmodule
